\"size\":100}},\"elements\":[],\"widgetType\":\"image\"},{\"id\":\"2e6bb89\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/20181217_115414.jpg\",\"id\":220}},\"elements\":[],\"widgetType\":\"image\"}],\"isInner\":false}],\"isInner\":false}]'),(1099,225,'_elementor_version','0.4'),(1100,225,'_elementor_css','a:4:{s:4:\"time\";i:1552588111;s:5:\"fonts\";a:0:{}s:6:\"status\";s:4:\"file\";i:0;s:0:\"\";}'),(1101,226,'_elementor_edit_mode','builder'),(1102,226,'_elementor_template_type','post'),(1103,226,'_wp_page_template','default'),(1104,226,'_elementor_data','[{\"id\":\"406ff57\",\"elType\":\"section\",\"settings\":[],\"elements\":[{\"id\":\"069c4c9\",\"elType\":\"column\",\"settings\":{\"_column_size\":100},\"elements\":[{\"id\":\"ec660f4\",\"elType\":\"widget\",\"settings\":{\"editor\":\"<p>A\\u00a0<b>cyclic redundancy check<\\/b>\\u00a0(<b>CRC<\\/b>) is an\\u00a0error-detecting code\\u00a0commonly used in digital\\u00a0networks\\u00a0and storage devices to detect accidental changes to raw data. Blocks of data entering these systems get a short\\u00a0<i>check value<\\/i>\\u00a0attached, based on the remainder of a\\u00a0polynomial division\\u00a0of their contents. On retrieval, the calculation is repeated and, in the event the check values do not match, corrective action can be taken against data corruption. (<a href=\\\"https:\\/\\/en.wikipedia.org\\/wiki\\/Cyclic_redundancy_check\\\" target=\\\"_blank\\\" rel=\\\"noopener\\\">Wikipedia<\\/a>)<\\/p><p>I wrote a VHDL code to simulate user input as a number of bits and shows the output with the CRC code attached on the LEDs of the intel DE2-70<\\/p>\"},\"elements\":[],\"widgetType\":\"text-editor\"},{\"id\":\"c81f681\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/CRC1-Diagram.png\",\"id\":205},\"caption_source\":\"custom\",\"caption\":\"Implementation of CRC-3\",\"_background_color\":\"#ffffff\"},\"elements\":[],\"widgetType\":\"image\"},{\"id\":\"18ae4d2\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/CRC0-Diagram.png\",\"id\":206},\"caption_source\":\"custom\",\"caption\":\"Implementation of CRC-5\",\"width\":{\"unit\":\"%\",\"size\":82}},\"elements\":[],\"widgetType\":\"image\"},{\"id\":\"e4573a2\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/CRC2-Diagram.png\",\"id\":207},\"caption_source\":\"custom\",\"caption\":\"Implementation of CRC-8\",\"width\":{\"unit\":\"%\",\"size\":100}},\"elements\":[],\"widgetType\":\"image\"},{\"id\":\"3b1a8ec\",\"elType\":\"widget\",\"settings\":{\"editor\":\"<p>I simulated the circuit using the software from Intel called Quartus and showed how it works perfectly as inteded:<\\/p>\"},\"elements\":[],\"widgetType\":\"text-editor\"},{\"id\":\"e7f701b\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/crc0-simulation.jpg\",\"id\":221},\"caption_source\":\"custom\",\"caption\":\"crc0 shows the CRC-3 code to be attached\",\"width\":{\"unit\":\"%\",\"size\":100}},\"elements\":[],\"widgetType\":\"image\"},{\"id\":\"e48e774\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/crc1-simulation.jpg\",\"id\":222},\"caption_source\":\"custom\",\"caption\":\"crc1 shows the CRC-5 code to be attached\",\"width\":{\"unit\":\"%\",\"size\":100}},\"elements\":[],\"widgetType\":\"image\"},{\"id\":\"68db586\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/crc2-simulation.jpg\",\"id\":223},\"caption_source\":\"custom\",\"caption\":\"crc2 shows the CRC-8 code to be attached\",\"width\":{\"unit\":\"%\",\"size\":100}},\"elements\":[],\"widgetType\":\"image\"},{\"id\":\"2dfa1e4\",\"elType\":\"widget\",\"settings\":{\"editor\":\"<p>I presented the circuit and code to the professor and demonstrated the how the code works on the DE2-70 board<\\/p>\"},\"elements\":[],\"widgetType\":\"text-editor\"},{\"id\":\"2e6bb89\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/20181217_115414.jpg\",\"id\":220}},\"elements\":[],\"widgetType\":\"image\"}],\"isInner\":false}],\"isInner\":false}]'),(1105,226,'_elementor_version','0.4'),(1106,211,'_elementor_edit_mode','builder'),(1107,211,'_elementor_template_type','post'),(1108,211,'_wp_page_template','default'),(1109,211,'_elementor_data','[{\"id\":\"dfaa647\",\"elType\":\"section\",\"settings\":[],\"elements\":[{\"id\":\"ed9ac74\",\"elType\":\"column\",\"settings\":{\"_column_size\":100},\"elements\":[{\"id\":\"53bd2ef\",\"elType\":\"widget\",\"settings\":{\"editor\":\"<p>We implemented an algorithm for tree pattern matching described in the IEEE paper \\\"<a href=\\\"https:\\/\\/ieeexplore.ieee.org\\/document\\/1598158\\\" target=\\\"_blank\\\" rel=\\\"noopener\\\">A Parallel Algorithm and Architecture for Object Recognition in Images<\\/a>\\\".<br \\/>We used VHDL to implement the algorithm, and we added our own designed components to control data flow through the circuit. The team consisted of 4 students, I was the leader of the group.<\\/p><p>We used ModelSim to simulate and test the VHDL code.<\\/p>\"},\"elements\":[],\"widgetType\":\"text-editor\"},{\"id\":\"4ee7213\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/complete-diagram.png\",\"id\":231},\"caption_source\":\"custom\",\"caption\":\"System block diagram\",\"width\":{\"unit\":\"%\",\"size\":82}},\"elements\":[],\"widgetType\":\"image\"},{\"id\":\"4d574a6\",\"elType\":\"widget\",\"settings\":{\"editor\":\"<p>The system proposed in the paper uses processing elements (PEs) to process the data serially and send the result back, we designed and added memory blocks that handle data input and a controller to handle data distribution and control of the different PEs and registers. The detailed diagrams of the top and bottom parts of the system are shown below.<\\/p>\"},\"elements\":[],\"widgetType\":\"text-editor\"},{\"id\":\"03299d8\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/top-part-diagram.png\",\"id\":233},\"caption_source\":\"custom\",\"caption\":\"Top part\",\"width\":{\"unit\":\"%\",\"size\":77}},\"elements\":[],\"widgetType\":\"image\"},{\"id\":\"71f3c9b\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/bottom-part-diagram.png\",\"id\":234},\"caption_source\":\"custom\",\"caption\":\"Bottom part\"},\"elements\":[],\"widgetType\":\"image\"},{\"id\":\"55fcf1a\",\"elType\":\"widget\",\"settings\":{\"editor\":\"<p>The controller is built using a state machine whose diagram is shown below.<\\/p>\"},\"elements\":[],\"widgetType\":\"text-editor\"},{\"id\":\"bc13b9e\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/State-Diagram.png\",\"id\":236}},\"elements\":[],\"widgetType\":\"image\"},{\"id\":\"5b84953\",\"elType\":\"widget\",\"settings\":{\"editor\":\"<p>In the end, we delivered a good system inspired by the paper and designed by us. Also, I gained very good experience in VHDL, and in working as part of a team on a challenging project.<\\/p>\"},\"elements\":[],\"widgetType\":\"text-editor\"},{\"id\":\"4acf407\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/20180508_210023.jpg\",\"id\":240}},\"elements\":[],\"widgetType\":\"image\"}],\"isInner\":false}],\"isInner\":false}]'),(1110,227,'_elementor_edit_mode','builder'),(1111,227,'_elementor_template_type','post'),(1112,227,'_wp_page_template','default'),(1113,227,'_elementor_data','[{\"id\":\"dfaa647\",\"elType\":\"section\",\"settings\":[],\"elements\":[{\"id\":\"ed9ac74\",\"elType\":\"column\",\"settings\":{\"_column_size\":100},\"elements\":[],\"isInner\":false}],\"isInner\":false}]'),(1114,211,'_elementor_version','0.4'),(1123,229,'_elementor_data','[{\"id\":\"dfaa647\",\"elType\":\"section\",\"settings\":[],\"elements\":[{\"id\":\"ed9ac74\",\"elType\":\"column\",\"settings\":{\"_column_size\":100},\"elements\":[{\"id\":\"53bd2ef\",\"elType\":\"widget\",\"settings\":{\"editor\":\"<p>We implemented an algorithm for tree pattern matching described in the IEEE paper \\\"<a href=\\\"https:\\/\\/ieeexplore.ieee.org\\/document\\/1598158\\\" target=\\\"_blank\\\" rel=\\\"noopener\\\">A Parallel Algorithm and Architecture for Object Recognition in Images<\\/a>\\\".<br \\/>We used VHDL to implement the algorithm, and we added our own designed components to control data flow through the circuit.<\\/p>\"},\"elements\":[],\"widgetType\":\"text-editor\"}],\"isInner\":false}],\"isInner\":false}]'),(1122,229,'_wp_page_template','default'),(1120,229,'_elementor_edit_mode','builder'),(1121,229,'_elementor_template_type','post'),(1124,229,'_elementor_version','0.4'),(1135,232,'_elementor_data','[{\"id\":\"dfaa647\",\"elType\":\"section\",\"settings\":[],\"elements\":[{\"id\":\"ed9ac74\",\"elType\":\"column\",\"settings\":{\"_column_size\":100},\"elements\":[{\"id\":\"53bd2ef\",\"elType\":\"widget\",\"settings\":{\"editor\":\"<p>We implemented an algorithm for tree pattern matching described in the IEEE paper \\\"<a href=\\\"https:\\/\\/ieeexplore.ieee.org\\/document\\/1598158\\\" target=\\\"_blank\\\" rel=\\\"noopener\\\">A Parallel Algorithm and Architecture for Object Recognition in Images<\\/a>\\\".<br \\/>We used VHDL to implement the algorithm, and we added our own designed components to control data flow through the circuit. The team consisted o