style-medium\";a:4:{s:4:\"file\";s:26:\"Project-Poster-520x292.jpg\";s:5:\"width\";i:520;s:6:\"height\";i:292;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:14:\"boxstyle-large\";a:4:{s:4:\"file\";s:26:\"Project-Poster-720x404.jpg\";s:5:\"width\";i:720;s:6:\"height\";i:404;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:13:\"boxstyle-list\";a:4:{s:4:\"file\";s:26:\"Project-Poster-320x320.jpg\";s:5:\"width\";i:320;s:6:\"height\";i:320;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:9:\"alx-small\";a:4:{s:4:\"file\";s:26:\"Project-Poster-200x200.jpg\";s:5:\"width\";i:200;s:6:\"height\";i:200;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:10:\"alx-medium\";a:4:{s:4:\"file\";s:26:\"Project-Poster-520x292.jpg\";s:5:\"width\";i:520;s:6:\"height\";i:292;s:9:\"mime-type\";s:10:\"image/jpeg\";}}s:10:\"image_meta\";a:12:{s:8:\"aperture\";s:1:\"0\";s:6:\"credit\";s:0:\"\";s:6:\"camera\";s:0:\"\";s:7:\"caption\";s:0:\"\";s:17:\"created_timestamp\";s:1:\"0\";s:9:\"copyright\";s:0:\"\";s:12:\"focal_length\";s:1:\"0\";s:3:\"iso\";s:1:\"0\";s:13:\"shutter_speed\";s:1:\"0\";s:5:\"title\";s:0:\"\";s:11:\"orientation\";s:1:\"0\";s:8:\"keywords\";a:0:{}}}'),(1280,263,'_elementor_edit_mode','builder'),(1281,263,'_elementor_template_type','post'),(1282,263,'_wp_page_template','default'),(1283,263,'_elementor_data','[{\"id\":\"8934367\",\"elType\":\"section\",\"settings\":[],\"elements\":[{\"id\":\"1711149\",\"elType\":\"column\",\"settings\":{\"_column_size\":100},\"elements\":[{\"id\":\"5bb2ad8\",\"elType\":\"widget\",\"settings\":{\"editor\":\"<p>We built a system that sees the position of a toy car using a camera fixed to the ceiling and drives it automatically to the desired location.<\\/p><p>We coded the system in MATLAB. We used image processing to identify the car\'s position and destination and we coded 3 different methods of control to guide the car to the destination.<\\/p><p>The image processing technique we used was background subtraction. This method easily detects the car since it\'s the only object moving in the environment. A Gaussian filter was applied to reduce the noise after subtraction and then a threshold was applied and the remaining pixel locations was averaged to get the car\'s location. The process is shown below.<\\/p>\"},\"elements\":[],\"widgetType\":\"text-editor\"},{\"id\":\"1fe0c25\",\"elType\":\"widget\",\"settings\":{\"carousel\":[{\"id\":249,\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/Car.png\"},{\"id\":250,\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/car2.png\"},{\"id\":251,\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/car3.png\"},{\"id\":252,\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/car4.png\"}],\"thumbnail_size\":\"large\",\"link_to\":\"file\",\"caption_type\":\"caption\",\"infinite\":\"no\",\"arrows_position\":\"outside\",\"arrows_color\":\"#000000\"},\"elements\":[],\"widgetType\":\"image-carousel\"},{\"id\":\"338ec03\",\"elType\":\"widget\",\"settings\":{\"editor\":\"<p>We used a cheap remote controlled toy car we bought from the local market and we modified its motor because it was too fast to be controlled accurately.<\\/p>\"},\"elements\":[],\"widgetType\":\"text-editor\"},{\"id\":\"fe4f927\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/Car.jpg\",\"id\":254},\"image_size\":\"medium\",\"link_to\":\"file\"},\"elements\":[],\"widgetType\":\"image\"},{\"id\":\"852f209\",\"elType\":\"widget\",\"settings\":{\"editor\":\"<p>To control the car we hacked its remote controller and made our own printed circuit board (PCB) so that we can connect the PC to the remote controller.<\\/p>\"},\"elements\":[],\"widgetType\":\"text-editor\"},{\"id\":\"f7c4b26\",\"elType\":\"widget\",\"settings\":{\"carousel\":[{\"id\":259,\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/20151109_161717-e1552616478298.jpg\"},{\"id\":260,\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/IMG-20151109-WA0002-e1552616585742.jpeg\"}],\"thumbnail_size\":\"medium_large\",\"navigation\":\"none\",\"link_to\":\"file\",\"arrows_position\":\"outside\",\"arrows_color\":\"#000000\",\"image_spacing\":\"custom\",\"image_spacing_custom\":{\"unit\":\"px\",\"size\":100},\"_padding\":{\"unit\":\"px\",\"top\":\"0\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"184\",\"isLinked\":false}},\"elements\":[],\"widgetType\":\"image-carousel\"},{\"id\":\"735812d\",\"elType\":\"widget\",\"settings\":{\"editor\":\"<p>The project was completed successfully and the system was able to control the car perfectly.<\\/p><p>Shown below is the project poster.<\\/p>\"},\"elements\":[],\"widgetType\":\"text-editor\"},{\"id\":\"a5a54a3\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/03\\/Project-Poster.jpg\",\"id\":262}},\"elements\":[],\"widgetType\":\"image\"}],\"isInner\":false}],\"isInner\":false}]'),(1284,263,'_elementor_version','0.4'),(1285,263,'_elementor_css','a:4:{s:4:\"time\";i:1552616816;s:5:\"fonts\";a:0:{}s:6:\"status\";s:4:\"file\";i:0;s:0:\"\";}'),(1287,264,'_elementor_template_type','post'),(1288,264,'_wp_page_template','default'),(1289,264,'_elementor_data','[{\"id\":\"8934367\",\"elType\":\"section\",\"settings\":[],\"elements\":[{\"id\":\"1711149\",\"elType\":\"column\",\"settings\":{\"_column_size\":100},\"elements\":[{\"id\":\"5bb2ad8\",\"elType\":\"widget\",\"settings\":{\"editor\":\"<p>We built a system that sees the position of a toy car using a camera fixed to the ceiling and drives it automatically to the desired location.<\\/p><p>We coded the system in MATLAB. We used image processing to identify the car\'s position and destination and we coded 3 different methods of control to guide the car to the destination.<\\/p><p>The image processing technique we used was background subtraction. This method easily detects the car si