13-200x200.jpg\";s:5:\"width\";i:200;s:6:\"height\";i:200;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:20:\"boxstyle-medium-orig\";a:4:{s:4:\"file\";s:31:\"IMG_20191230_120713-520x292.jpg\";s:5:\"width\";i:520;s:6:\"height\";i:292;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:19:\"boxstyle-large-orig\";a:4:{s:4:\"file\";s:31:\"IMG_20191230_120713-720x404.jpg\";s:5:\"width\";i:720;s:6:\"height\";i:404;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:18:\"boxstyle-list-orig\";a:4:{s:4:\"file\";s:31:\"IMG_20191230_120713-320x320.jpg\";s:5:\"width\";i:320;s:6:\"height\";i:320;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:14:\"alx-small-orig\";a:4:{s:4:\"file\";s:31:\"IMG_20191230_120713-200x200.jpg\";s:5:\"width\";i:200;s:6:\"height\";i:200;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:15:\"alx-medium-orig\";a:4:{s:4:\"file\";s:31:\"IMG_20191230_120713-520x292.jpg\";s:5:\"width\";i:520;s:6:\"height\";i:292;s:9:\"mime-type\";s:10:\"image/jpeg\";}}'),(1641,333,'_elementor_version','0.4'),(1675,323,'_oembed_3c26c8ca5f7d8d232c5ff9ccabe7f0cf','{{unknown}}'),(1643,334,'_elementor_edit_mode','builder'),(1644,334,'_elementor_template_type','post'),(1645,334,'_wp_page_template','default'),(1646,334,'_elementor_data','[{\"id\":\"ad94a4d\",\"elType\":\"section\",\"settings\":[],\"elements\":[{\"id\":\"ca5d9ce\",\"elType\":\"column\",\"settings\":{\"_column_size\":100},\"elements\":[{\"id\":\"b48047a\",\"elType\":\"widget\",\"settings\":{\"editor\":\"<p>I wanted to connect the AC thermostat in the house we are living in right now to the internet so we can control it through our phones instead of having to do it manually. So I designed and built a system to do that.<\\/p><p>I designed a mechanical module with a servo motor that can be taped on the thermostat to control it, and I connected the servo motor to the ESP01 micro controller. ESP01 is an IOT micro controller that can be programmed using different methods, I programmed it using the Arduion IDE.<\\/p><p>I used an APP called Blynk to to connect to the phone because it\'s free and it provides a very good GUI.<\\/p><p>Since we are not the owners of the house, I didn\'t want to change anything in the wiring of the thermostat or do any permanent changes.<\\/p>\"},\"elements\":[],\"widgetType\":\"text-editor\"},{\"id\":\"64a2157\",\"elType\":\"widget\",\"settings\":{\"carousel\":[{\"id\":330,\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/12\\/IMG_20191230_120557.jpg\"},{\"id\":331,\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/12\\/IMG_20191230_120622-e1577755468609.jpg\"},{\"id\":332,\"url\":\"http:\\/\\/waseemorphali.com\\/wp-content\\/uploads\\/2019\\/12\\/IMG_20191230_120713-e1577755480682.jpg\"}],\"thumbnail_size\":\"boxstyle-list\",\"link_to\":\"file\",\"image_spacing\":\"custom\",\"image_border_border\":\"solid\"},\"elements\":[],\"widgetType\":\"image-carousel\"}],\"isInner\":false}],\"isInner\":false}]'),(1647,334,'_elementor_version','0.4'),(1648,334,'_elementor_css','a:5:{s:4:\"time\";i:1577755664;s:5:\"fonts\";a:0:{}s:6:\"status\";s:5:\"empty\";i:0;s:0:\"\";s:3:\"css\";s:0:\"\";}'),(1650,335,'_wp_page_template','default'),(1651,335,'_elementor_template_type','post'),(1652,335,'_elementor_data','[{\"id\":\"912d426\",\"elType\":\"section\",\"settings\":[],\"elements\":[{\"id\":\"845857d\",\"elType\":\"column\",\"settings\":{\"_column_size\":100},\"elements\":[{\"id\":\"7e3adbd\",\"elType\":\"widget\",\"settings\":{\"title\":\"Education\",\"title_color\":\"rgba(0,0,0,0.99)\",\"typography_typography\":\"custom\",\"typography_font_family\":\"Arial\",\"link\":{\"url\":\"http:\\/\\/waseemorphali.com\\/education\\/\",\"is_external\":\"\",\"nofollow\":\"\"}},\"elements\":[],\"widgetType\":\"heading\"},{\"id\":\"f9ad5d4\",\"elType\":\"section\",\"settings\":{\"structure\":\"20\"},\"elements\":[{\"id\":\"f8e4df6\",\"elType\":\"column\",\"settings\":{\"_column_size\":50},\"elements\":[{\"id\":\"a2e1690\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/